using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddSingleton<Notebook>();

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<ResearchAgentRunner>();

var host = builder.Build();

var runner = host.Services.GetRequiredService<ResearchAgentRunner>();

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

await runner.RunAsync(topic, CancellationToken.None);

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(topic)
        ? throw new InvalidOperationException("A research topic is required.")
        : topic;
}

// --- Services ---

/// <summary>Persistent notebook that accumulates research notes across agent turns.</summary>
public sealed class Notebook
{
    private readonly List<NoteEntry> _notes = [];

    public void Add(string title, string content)
    {
        _notes.Add(new NoteEntry(title, content, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note saved: {title}");
    }

    public IReadOnlyList<NoteEntry> Notes => _notes.AsReadOnly();

    public string Summarize()
    {
        if (_notes.Count == 0) return "(no notes taken)";
        return string.Join("\n\n", _notes.Select((n, i) =>
            $"[{i + 1}] {n.Title}\n{n.Content}"));
    }
}

public sealed record NoteEntry(string Title, string Content, DateTime Timestamp);

/// <summary>Tool functions exposed to the agent.</summary>
public sealed class ResearchTools(Notebook notebook)
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(30),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "application/json" },
        },
    };

    [Description("Search the web for information on a query. Returns a JSON array of search results with title, url, and snippet.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<object>();

            if (root.TryGetProperty("Abstract", out var abs) &&
                abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = root.TryGetProperty("AbstractSource", out var s) ? s.GetString() : "Unknown";
                var absUrl = root.TryGetProperty("AbstractURL", out var u) ? u.GetString() : "";
                results.Add(new { title = $"Summary from {source}", url = absUrl, snippet = abstractText });
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } topicText)
                    {
                        var topicUrl = topic.TryGetProperty("FirstURL", out var tu) ? tu.GetString() : "";
                        results.Add(new { title = topicText[..Math.Min(80, topicText.Length)], url = topicUrl, snippet = topicText });
                    }
                }
            }

            if (results.Count == 0)
                return JsonSerializer.Serialize(new[] { new { title = "No results", url = "", snippet = $"No results found for '{query}'. Try rephrasing." } });

            return JsonSerializer.Serialize(results);
        }
        catch (Exception ex)
        {
            return JsonSerializer.Serialize(new[] { new { title = "Search error", url = "", snippet = ex.Message } });
        }
    }

    [Description("Save a research note with a title and content. Use this to record important findings during research.")]
    public void SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        notebook.Add(title, content);
    }

    [Description("Retrieve all notes saved so far. Returns the full notebook contents.")]
    public string GetNotes()
    {
        Console.WriteLine("  📖 Reading notebook...");
        return notebook.Summarize();
    }
}

/// <summary>Orchestrates the research agent loop.</summary>
public sealed class ResearchAgentRunner(IChatClient chatClient, Notebook notebook)
{
    public async Task RunAsync(string topic, CancellationToken ct)
    {
        var tools = new ResearchTools(notebook);

        var agent = new ChatClientAgent(
            chatClient,
            $"""
            You are a research agent. Your goal is to thoroughly research the given topic
            by searching the web and taking structured notes on your findings.

            Workflow:
            1. Break the topic into 2-3 key sub-questions.
            2. Search the web for each sub-question.
            3. Save important findings as notes using SaveNote.
            4. After gathering enough information, retrieve your notes with GetNotes.
            5. Provide a final comprehensive summary of your research.

            Be thorough but concise. Cite sources when possible.
            """,
            "ResearchAgent");

        agent.Tools = [.. AIFunctionFactory.Create(tools.SaveNote),
                        AIFunctionFactory.Create(tools.GetNotes),
                        AIFunctionFactory.Create(ResearchTools.SearchWeb)];

        var history = new List<ChatMessage>
        {
            new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
        };

        var options = new AgentInvokeOptions
        {
            MaximumIterations = 10,
        };

        ChatMessage? finalResponse = null;

        await foreach (var message in agent.InvokeStreamingAsync(history, options, ct))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            {
                finalResponse = message;
            }
        }

        Console.WriteLine("\n" + new string('═', 60));
        Console.WriteLine("📋 RESEARCH SUMMARY");
        Console.WriteLine(new string('═', 60));

        if (finalResponse is not null)
        {
            Console.WriteLine(finalResponse.Text);
        }
        else
        {
            Console.WriteLine(notebook.Summarize());
        }

        Console.WriteLine(new string('═', 60));
        Console.WriteLine($"📝 Total notes taken: {notebook.Notes.Count}");
    }
}

