 public sealed record NoteEntry(string Title, string Content, DateTime Timestamp);

 /// <summary>Tool functions exposed to the agent.</summary>
 public sealed class ResearchTools(Notebook notebook)
 {
     private static readonly HttpClient Http = new()
     {
         Timeout = TimeSpan.FromSeconds(30),
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0" },
             { "Accept", "application/json" },
         },
     };

     [Description("Search the web for information on a query. Returns a JSON array of search results with title, url, and snippet.")]
     public static async Task<string> SearchWeb(
         [Description("The search query string")] string query)
     {
         Console.WriteLine($"  🌐 Searching: {query}");

         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
             var json = await Http.GetStringAsync(url);
             using var doc = JsonDocument.Parse(json);
             var root = doc.RootElement;

             var results = new List<object>();

             if (root.TryGetProperty("Abstract", out var abs) &&
                 abs.GetString() is { Length: > 0 } abstractText)
             {
                 var source = root.TryGetProperty("AbstractSource", out var s) ? s.GetString() : "Unknown";
                 var absUrl = root.TryGetProperty("AbstractURL", out var u) ? u.GetString() : "";
                 results.Add(new { title = $"Summary from {source}", url = absUrl, snippet = abstractText });
             }

             if (root.TryGetProperty("RelatedTopics", out var topics))
             {
                 foreach (var topic in topics.EnumerateArray().Take(8))
                 {
                     if (topic.TryGetProperty("Text", out var text) &&
                         text.GetString() is { Length: > 0 } topicText)
                     {
                         var topicUrl = topic.TryGetProperty("FirstURL", out var tu) ? tu.GetString() : "";
                         results.Add(new { title = topicText[..Math.Min(80, topicText.Length)], url = topicUrl, snippet = topicText });
                     }
                 }
             }

             if (results.Count == 0)
                 return JsonSerializer.Serialize(new[] { new { title = "No results", url = "", snippet = $"No results found for '{query}'. Try rephrasing." } });

             return JsonSerializer.Serialize(results);
         }
         catch (Exception ex)
         {
             return JsonSerializer.Serialize(new[] { new { title = "Search error", url = "", snippet = ex.Message } });
         }
     }

     [Description("Save a research note with a title and content. Use this to record important findings during research.")]
     public void SaveNote(
         [Description("Short descriptive title for the note")] string title,
         [Description("Detailed content of the note")] string content)
